import boto3
import json
import os
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
from botocore.config import Config

# Load AWS credentials securely
aws_access_key_id = os.getenv('AWS_ACCESS_KEY_ID')
aws_secret_access_key = os.getenv('AWS_SECRET_ACCESS_KEY')
aws_region = os.getenv('AWS_REGION', 'us-east-1')

# Validate AWS credentials
if not aws_access_key_id or not aws_secret_access_key:
    raise ValueError("AWS credentials are not set properly.")

# Create SQS client with secure configurations
sqs_client = boto3.client(
    'sqs',
    region_name=aws_region,
    aws_access_key_id=aws_access_key_id,
    aws_secret_access_key=aws_secret_access_key,
    config=Config(
        retries={
            'max_attempts': 10,
            'mode': 'standard'
        }
    )
)

# SQS Queue URL
queue_url = os.getenv('SQS_QUEUE_URL')

def validate_user_data(user_data):
    # Implement validation logic for user data
    if not isinstance(user_data, dict):
        raise ValueError("User data must be a dictionary.")
    required_keys = {'email', 'phone', 'address'}
    if not required_keys.issubset(user_data.keys()):
        raise ValueError("User data must include email, phone, and address.")
    # Add more validation as needed

def publish_message(user_data):
    try:
        validate_user_data(user_data)
        
        # Serialize user data to JSON
        message_body = json.dumps(user_data)
        
        # Send message to SQS
        response = sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body
        )
        return response
    except (NoCredentialsError, PartialCredentialsError) as e:
        print("Credential error:", e)
    except Exception as e:
        print("An error occurred:", e)

# Example usage
user_data = {
    'email': 'user@example.com',
    'phone': '+1234567890',
    'address': '123 Main St, Anytown, USA'
}

response = publish_message(user_data)
print(response)